fun getCity(input: String?): String {
    return input ?: "Unknown"
}
println(getCity(null))
println(getCity("Tokyo"))

fun printLength(s: String?) {
    if (s == null) return
    println(s.length)
}
printLength("Kotlin")

val value: String? = null
value?.let {
    println("Block ran: $it")
}
println("After")

fun getLength(s: String?): Int {
    val str = s ?: return -1
    return str.length
}
println(getLength(null))
println(getLength("hello"))
